24	export class BayesApiError extends Error {
25	  constructor(
26	    public status: number,
27	    public code: string,
28	    public details: Record<string, unknown> = {},
29	  ) {
30	    super(`${code}: ${status}`);
31	    this.name = "BayesApiError";
32	  }
33	}
