159	export function getMarketPricesWebSocketUrl(marketId: string): string {
160	  const baseUrl = API_BASE
161	    ? new URL(API_BASE, window.location.origin)
162	    : new URL(window.location.origin);
163	  const socketUrl = new URL(baseUrl.toString());
164	  socketUrl.protocol = socketUrl.protocol === "https:" ? "wss:" : "ws:";
165	  socketUrl.pathname = joinUrlPath(
166	    socketUrl.pathname,
167	    `/ws/markets/${encodeURIComponent(marketId)}/prices`,
168	  );
169	  socketUrl.search = "";
170	  socketUrl.hash = "";
171	  return socketUrl.toString();
172	}
