14	function getErrorMessage(error: unknown, fallback: string): string {
15	  return error instanceof Error ? error.message : fallback;
16	}
17	
18	function formatSignedSize(value: number): string {
19	  if (value > 0) return `+${value.toFixed(2)}`;
20	  return value.toFixed(2);
