23	export default function Portfolio() {
24	  const { session, isConfigured } = useSession();
25	  const exposureQuery = useAccountExposure(session.accountId);
26	  const riskQuery = useAccountRisk(session.accountId);
27	  const marketsQuery = useMarkets();
28	  const marketTitles = new Map(
29	    (marketsQuery.data?.markets ?? []).map((market): [string, string] => [market.id, market.title]),
30	  );
31	
32	  if (!isConfigured) {
33	    return (
34	      <div style={{ textAlign: "center", padding: "var(--space-xl)", color: "var(--color-text-muted)" }}>
35	        Set your Account ID in the header to view your portfolio.
36	      </div>
37	    );
38	  }
39	
40	  const exposure = exposureQuery.data?.account.exposure;
41	  const risk = riskQuery.data?.account.risk;
42	  const hasExposure = exposure != null;
43	  const hasRisk = risk != null;
44	  const exposureMissing = isAccountNotFoundError(exposureQuery.error);
45	  const riskMissing = isAccountNotFoundError(riskQuery.error);
46	  const exposurePending = !hasExposure && exposureQuery.isPending;
47	  const riskPending = !hasRisk && riskQuery.isPending;
48	  const exposureError = exposureQuery.error && !exposureMissing ? exposureQuery.error : null;
49	  const riskError = riskQuery.error && !riskMissing ? riskQuery.error : null;
50	  const hasNoAccountData = !hasExposure && !hasRisk;
51	  const waitingForMissingAccountCompanion = hasNoAccountData
52	    && ((exposureMissing && riskPending) || (riskMissing && exposurePending));
53	  const positions = [...(exposure?.positions ?? [])].sort(
54	    (left, right) => new Date(right.updatedAt).getTime() - new Date(left.updatedAt).getTime(),
55	  );
56	
57	  if (hasNoAccountData && ((exposurePending && riskPending) || waitingForMissingAccountCompanion)) {
58	    return <LoadingPage />;
59	  }
60	
61	  if (hasNoAccountData && exposureMissing && riskMissing) {
62	    return <ErrorMessage message="Account not found or no positions yet." />;
63	  }
64	
65	  if (hasNoAccountData && (exposureError || riskError)) {
66	    return (
67	      <ErrorMessage
68	        message={getErrorMessage(exposureError ?? riskError, "Unable to load portfolio.")}
69	      />
70	    );
71	  }
72	
73	  const cap = risk?.capacityIndicators;
74	  const healthColor = cap?.status === "healthy" ? "var(--color-success)"
75	    : cap?.status === "warning" ? "var(--color-warning)"
76	    : "var(--color-danger)";
77	
78	  return (
79	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
80	      <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>Portfolio</h1>
81	
82	      {risk && cap && (
83	        <div style={{ display: "grid", gap: "var(--space-sm)" }}>
84	          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: "var(--space-md)" }}>
85	            <MetricCard label="Limit" value={cap.limit.toFixed(2)} />
86	            <MetricCard label="Available" value={cap.available.toFixed(2)} />
87	            <MetricCard label="Consumed" value={cap.consumed.toFixed(2)} />
88	            <MetricCard label="Utilization" value={`${(cap.utilization * 100).toFixed(1)}%`} />
89	            <MetricCard label="Health" value={cap.status} color={healthColor} />
90	            <MetricCard label="Min Asset (Overall)" value={risk.minAssets.overall.toFixed(2)} />
91	          </div>
92	          {risk.updatedAt && (
93	            <div style={{ fontSize: "0.7rem", color: "var(--color-text-muted)" }}>
94	              Last updated: {new Date(risk.updatedAt).toLocaleString()}
95	            </div>
96	          )}
97	        </div>
98	      )}
99	
100	      {riskError && (
101	        <ErrorMessage message={getErrorMessage(riskError, "Unable to load risk metrics.")} />
102	      )}
103	
104	      <div>
105	        <h2 style={{ fontSize: "1.1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>Live Outcome Holdings</h2>
106	        {exposurePending ? (
107	          <span style={{ color: "var(--color-text-muted)" }}>Loading live holdings...</span>
108	        ) : exposureError ? (
109	          <ErrorMessage message={getErrorMessage(exposureError, "Unable to load live holdings.")} />
110	        ) : positions.length === 0 ? (
111	          <span style={{ color: "var(--color-text-muted)" }}>No live EventTrade positions.</span>
112	        ) : (
113	          <div style={{ borderRadius: "var(--radius-md)", border: "1px solid var(--color-border)", overflow: "hidden" }}>
114	            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
115	              <thead>
116	                <tr style={{ background: "var(--color-bg-hover)" }}>
117	                  <th style={thStyle}>Market</th>
118	                  <th style={thStyle}>Outcome</th>
119	                  <th style={thStyle}>Net Size</th>
120	                  <th style={thStyle}>Abs Size</th>
121	                  <th style={thStyle}>Last Price</th>
122	                  <th style={thStyle}>Updated</th>
123	                </tr>
124	              </thead>
125	              <tbody>
126	                {positions.map((position) => (
127	                  <tr key={`${position.marketId}:${position.outcomeId}`} style={{ borderTop: "1px solid var(--color-border)" }}>
128	                    <td style={tdStyle}>
129	                      <Link to={`/markets/${position.marketId}`}>
130	                        {marketTitles.get(position.marketId) ?? position.marketId}
131	                      </Link>
132	                    </td>
133	                    <td style={{ ...tdStyle, fontFamily: "var(--font-mono)" }}>{position.outcomeId}</td>
134	                    <td style={{ ...tdStyle, fontFamily: "var(--font-mono)" }}>{formatSignedSize(position.netSize)}</td>
135	                    <td style={{ ...tdStyle, fontFamily: "var(--font-mono)" }}>{position.absSize.toFixed(2)}</td>
136	                    <td style={{ ...tdStyle, fontFamily: "var(--font-mono)" }}>{formatProbability(position.lastTradePrice)}</td>
137	                    <td style={tdStyle}>{formatRelativeTime(position.updatedAt)}</td>
138	                  </tr>
139	                ))}
140	              </tbody>
141	            </table>
142	          </div>
143	        )}
144	      </div>
145	    </div>
146	  );
147	}
