42	async function request<T>(
43	  path: string,
44	  options: RequestInit = {},
45	  session?: Session,
46	): Promise<T> {
47	  const headers: Record<string, string> = {
48	    ...(options.headers as Record<string, string>),
49	  };
50	
51	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
52	    headers["Content-Type"] = "application/json";
53	  }
54	
55	  if (session?.agentId) {
56	    headers["X-Bayes-Agent-Id"] = session.agentId;
57	  }
58	
59	  const res = await fetch(`${API_BASE}${path}`, {
60	    ...options,
61	    headers,
62	  });
63	
64	  const body = await res.json();
65	
66	  if (!res.ok) {
67	    const err = body as ApiError;
68	    throw new BayesApiError(
69	      res.status,
70	      err.error?.code ?? "unknown_error",
71	      err.error?.details ?? {},
72	    );
73	  }
74	
75	  return body as T;
76	}
