153	function joinUrlPath(basePath: string, path: string): string {
154	  const normalizedBase = basePath === "/" ? "" : basePath.replace(/\/$/, "");
155	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
156	  return `${normalizedBase}${normalizedPath}`;
157	}
