22	const API_BASE = import.meta.env.VITE_API_BASE ?? "";
23	
24	export class BayesApiError extends Error {
25	  constructor(
26	    public status: number,
27	    public code: string,
28	    public details: Record<string, unknown> = {},
29	  ) {
30	    super(`${code}: ${status}`);
31	    this.name = "BayesApiError";
32	  }
33	}
34	
35	export interface NormalizedMarketListFilters {
36	  status?: string;
37	  includeResolved?: true;
38	  sort?: string;
39	  q?: string;
40	}
41	
42	async function request<T>(
43	  path: string,
44	  options: RequestInit = {},
45	  session?: Session,
46	): Promise<T> {
47	  const headers: Record<string, string> = {
48	    ...(options.headers as Record<string, string>),
49	  };
50	
51	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
52	    headers["Content-Type"] = "application/json";
53	  }
54	
55	  if (session?.agentId) {
56	    headers["X-Bayes-Agent-Id"] = session.agentId;
57	  }
58	
59	  const res = await fetch(`${API_BASE}${path}`, {
60	    ...options,
61	    headers,
62	  });
63	
64	  const body = await res.json();
65	
66	  if (!res.ok) {
67	    const err = body as ApiError;
68	    throw new BayesApiError(
69	      res.status,
70	      err.error?.code ?? "unknown_error",
71	      err.error?.details ?? {},
72	    );
73	  }
74	
75	  return body as T;
76	}
77	
78	export function normalizeMarketListFilters(
79	  filters?: MarketListFilterInput,
80	): NormalizedMarketListFilters {
81	  const status = typeof filters === "string"
82	    ? filters
83	    : filters?.status;
84	  const includeResolved = (
85	    typeof filters !== "string"
86	    && filters?.includeResolved === true
